mapper.select:
SELECT o.order_id, o.order_no, u.username, h.hotel_name, h.city, h.district, o.check_in_date, o.check_out_date, o.total_price, o.pay_price, o.status, o.created_at FROM t_order o JOIN t_user u ON u.user_id = o.user_id JOIN t_hotel h ON h.hotel_id = o.hotel_id
o.status = #{status}
ORDER BY o.created_at DESC
